pub fn foo_if_fizz(fizzish: &str) -> &str {
    if fizzish == "fizz" {
        "foo"
    } else if fizzish == "fuzz" {
        "bar"
    } else {
        "baz"
    }
}

fn main() {
    println!("{}", foo_if_fizz("fizz"));
    println!("{}", foo_if_fizz("fuzz"));
    println!("{}", foo_if_fizz("other"));
}
